#include <stdio.h>
#include <string.h>
#include <stdint.h>

static long long dp[20][3][2];
static int digits[20];
static int len;

long long dfs(int pos, int mod, int tight) {
    if (pos == len) return mod == 0 ? 1 : 0;
    long long *memo = &dp[pos][mod][tight];
    if (*memo != -1) return *memo;
    long long res = 0;
    int limit = tight ? digits[pos] : 9;
    for (int d = 0; d <= limit; ++d) {
        int ntight = tight && (d == limit);
        res += dfs(pos + 1, (mod + d) % 3, ntight);
    }
    return *memo = res;
}

long long count_upto(long long x) {
    if (x < 0) return 0;
    len = 0;
    // extract digits
    char buf[32];
    sprintf(buf, "%lld", x);
    len = strlen(buf);
    for (int i = 0; i < len; ++i) digits[i] = buf[i] - '0';
    memset(dp, -1, sizeof(dp));
    return dfs(0, 0, 1);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long L, R; scanf("%lld %lld", &L, &R);
        long long ans = count_upto(R) - count_upto(L - 1);
        printf("%lld\n", ans);
    }
    return 0;
}

