import java.io.*;
import java.util.*;

public class Main {
    static long[][][] dp;
    static int[] digits;
    static int len;

    static long dfs(int pos, int mod, int tight) {
        if (pos == len) return mod == 0 ? 1 : 0;
        if (dp[pos][mod][tight] != -1) return dp[pos][mod][tight];
        long res = 0;
        int limit = tight == 1 ? digits[pos] : 9;
        for (int d = 0; d <= limit; d++) {
            int ntight = (tight == 1 && d == limit) ? 1 : 0;
            res += dfs(pos + 1, (mod + d) % 3, ntight);
        }
        dp[pos][mod][tight] = res;
        return res;
    }

    static long countUpto(long x) {
        if (x < 0) return 0;
        String s = Long.toString(x);
        len = s.length();
        digits = new int[len];
        for (int i = 0; i < len; i++) digits[i] = s.charAt(i) - '0';
        dp = new long[len][3][2];
        for (int i = 0; i < len; i++)
            for (int j = 0; j < 3; j++)
                Arrays.fill(dp[i][j], -1);
        return dfs(0, 0, 1);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long L = Long.parseLong(st.nextToken());
            long R = Long.parseLong(st.nextToken());
            long ans = countUpto(R) - countUpto(L - 1);
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

