import sys

def count_upto(x: int) -> int:
    if x < 0:
        return 0
    s = str(x)
    n = len(s)
    from functools import lru_cache
    @lru_cache(maxsize=None)
    def dfs(pos: int, mod: int, tight: bool) -> int:
        if pos == n:
            return 1 if mod == 0 else 0
        limit = int(s[pos]) if tight else 9
        total = 0
        for d in range(limit + 1):
            total += dfs(pos + 1, (mod + d) % 3, tight and d == limit)
        return total
    return dfs(0, 0, True)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        L = int(next(it)); R = int(next(it))
        ans = count_upto(R) - count_upto(L - 1)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

