function countUpto(x) {
  if (x < 0) return 0n;
  const s = x.toString();
  const n = s.length;
  const memo = new Map();
  function dfs(pos, mod, tight) {
    if (pos === n) return mod === 0 ? 1n : 0n;
    const key = pos + ',' + mod + ',' + (tight ? 1 : 0);
    if (memo.has(key)) return memo.get(key);
    const limit = tight ? Number(s[pos]) : 9;
    let res = 0n;
    for (let d = 0; d <= limit; d++) {
      res += dfs(pos + 1, (mod + d) % 3, tight && d === limit);
    }
    memo.set(key, res);
    return res;
  }
  return dfs(0, 0, true);
}
